('I20', 'P02', 'Over/under-staffing reduction', 'Reducción de sobre/sub-dotación', 'Réduction du sur/sous-effectif', '%', 0.03, 0.03, 0.03, 'user_input', 'manual', 20, true),
('I21', 'P06', 'HR ops hours/week saved', 'Horas/semana ahorradas en ops RRHH', 'Heures/semaine économisées en ops RH', 'h/week', 3, 3, 3, 'user_input', 'manual', 21, true),
('I22', 'P07', 'Hours/week saved on leave management', 'Horas/semana ahorradas en gestión de ausencias', 'Heures/semaine économisées en gestion des congés', 'h/week', 4, 4, 4, 'user_input', 'manual', 22, true),
('I23', 'P11a', 'Hours saved per month on reporting', 'Horas ahorradas al mes en reporting', 'Heures économisées par mois en reporting', 'h', 8, 8, 8, 'user_input', 'manual', 23, true),
('I24', 'P09', 'Days saved on time-to-productivity per new hire', 'Días ahorrados en tiempo-hasta-productividad por nueva incorporación', 'Jours économisés sur le temps de productivité par nouvelle recrue', 'days', 30, 30, 30, 'user_input', 'manual', 24, true),
('I25', 'P10', 'Manager hours saved per review cycle', 'Horas de manager ahorradas por ciclo de evaluación', 'Heures manager économisées par cycle d''évaluation', 'h', 4, 4, 4, 'user_input', 'manual', 25, true),
('I26', 'P08', 'Months delay avoided before acting on under-performance', 'Meses de retraso evitados antes de actuar sobre bajo rendimiento', 'Mois de retard évités avant d''agir sur la sous-performance', 'months', 4, 4, 4, 'user_input', 'manual', 26, true),
('I27', 'P08', '% of employees impacted by performance / engagement issues per year', '% de empleados afectados por problemas de rendimiento / engagement al año', '% d''employés impactés par des problèmes de performance / engagement par an', '%', 0.05, 0.05, 0.05, 'user_input', 'manual', 27, false),
